import{_ as l,c as a,o as i,ae as r}from"./chunks/framework.Cqi9LMMK.js";const d=JSON.parse('{"title":"Релиз 2.4.0","description":"","frontmatter":{"title":"Релиз 2.4.0"},"headers":[],"relativePath":"releases/2.4.0.md","filePath":"releases/2.4.0.md"}'),o={name:"releases/2.4.0.md"};function t(s,e,n,h,u,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="_2-4-0-2026-04-19-сделано" tabindex="-1">[2.4.0] - 2026-04-19 - Сделано <a class="header-anchor" href="#_2-4-0-2026-04-19-сделано" aria-label="Permalink to &quot;[2.4.0] - 2026-04-19 - Сделано&quot;">​</a></h2><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Таблица Network переведена на виртуализацию для ускорения работы и снижения фризов;</li><li>Изменено стартовое окно при открытии детализации запроса — по умолчанию теперь открывается Response;</li><li>При срабатывании breakpoint остановленный метод автоматически открывается на вкладке Request;</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p>Значительно ускорена работа с Props, что позволяет безопасно использовать автообновление данных;</p></li><li><p>В таблице Props колонка Props заменена на Passed и Declared (все колонки доступны для скрытия):</p><ul><li>Passed — количество Props, полученных в текущий момент;</li><li>Declared — количество возможных Props, объявленных для элемента;</li></ul></li><li><p>В блоке Details Props добавлен параметр Size;</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (Props Inspector) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (Props Inspector)&quot;">​</a></h4><ul><li>Добавлен режим выбора элементов на странице по аналогии с Chrome DevTools Elements;</li><li>Позволяет выбрать элемент прямо на странице и быстро отфильтровать список Props;</li><li>Подсвечивает Vue-компоненты при наведении;</li><li>Показывает краткую информацию об элементе: <strong>Name</strong>, <strong>Root element</strong>, <strong>Received Props</strong>, <strong>Nested components</strong>;</li><li>После выбора отображает Props только выбранного элемента и его вложенных компонентов;</li><li>Фильтр можно быстро сбросить через бейдж <strong>Filtered</strong>;</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="оконныи-режим" tabindex="-1">Оконный режим <a class="header-anchor" href="#оконныи-режим" aria-label="Permalink to &quot;Оконный режим&quot;">​</a></h4><ul><li>Добавлена поддержка оконного режима приложения с сохранением выбранного положения для обеих версий запуска;</li><li>Обновлён шеврон открытия iframe — добавлена иконка перетаскивания;</li><li>Добавлена возможность закрепления шеврона по любой из четырёх сторон браузера с автоматическим растягиванием окна приложения по высоте;</li></ul><h4 id="настроики-автозапуска" tabindex="-1">Настройки автозапуска <a class="header-anchor" href="#настроики-автозапуска" aria-label="Permalink to &quot;Настройки автозапуска&quot;">​</a></h4><ul><li>Добавлена возможность задать список сайтов для автоматического запуска приложения (Whitelist) и список исключений, где запуск приложения и отображение шеврона запрещены (Blacklist);</li><li>Добавлено popup-меню расширения с быстрыми действиями: <ul><li>Forced Launch — принудительный запуск приложения;</li><li>Reset Settings — полный сброс пользовательских настроек;</li></ul></li></ul><h4 id="прочие-улучшения-интерфеиса" tabindex="-1">Прочие улучшения интерфейса <a class="header-anchor" href="#прочие-улучшения-интерфеиса" aria-label="Permalink to &quot;Прочие улучшения интерфейса&quot;">​</a></h4><ul><li>Исправлены стили JSON для больших объёмов данных;</li><li>Добавлена возможность точного поиска при вводе значения в кавычках &quot;&quot;; без кавычек поиск работает в режиме like;</li><li>Внесены мелкие визуальные правки интерфейса;</li><li>Доработана логика закрытия вкладок по клавише Esc в режиме Devtools. Теперь сначала выполняется выход из вкладок и если закрывать больше нечего - будет открываться консоль Devtools;</li></ul><hr><h3 id="производительность" tabindex="-1">Производительность <a class="header-anchor" href="#производительность" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменён механизм определения Props и Store — получение данных значительно ускорено;</li><li>Увеличены лимиты на максимальное количество вычитываемых Props;</li><li>Проведён рефакторинг внутренней структуры проекта: удалены неиспользуемые модули, мёртвый код и дублирующая логика;</li></ul><hr><h3 id="документация" tabindex="-1">Документация <a class="header-anchor" href="#документация" aria-label="Permalink to &quot;Документация&quot;">​</a></h3><p>У проекта появилась полноценная документация; На лендинговой странице добавлен раздел с Documantation; В разделе Options → About добавлен быстрый переход к документации;</p><hr><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Заблокирована работа стандартного ПКМ внутри контекстного меню приложения;</li></ul>',25)])])}const P=l(o,[["render",t]]);export{d as __pageData,P as default};
